INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-f29af906-moex-00288', 'elementary-f29af906', 'elementary-f29af906-moex-113-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「我第一遭清楚看到這群水鳥的眼神。每一隻濱鷸的眼神，充滿著陌生、不馴與無可言喻的 神祕。對於賞鳥人而言，眼神是鳥最生動、也最無法觀察的地方。拍攝野鳥的人也以抓住牠 的眼神為第一要素。這是我第一次強烈感受牠們身上散發出的光澤，從來沒有見過如此純然 灰褐的色彩。這種平實的灰褐一直是牠們忍受酷寒，免受敵害，保護牠們從北方千里迢迢抵 臨的顏色。灰褐代表了安全，也象徵著遷徙、旅行、流浪冒險的顏色。這種顏色不是底片或 是顏料所能拍攝、渲染得體，完滿表達出來的。」 下列敘述，符合上文觀點的是：', '["濱鷸平實的顏色，同時代表流浪冒險與安全", "找到最近的觀察距離，是拍攝野鳥的第一要素", "對賞鳥人而言，濱鷸最大的特色是身上散發出的光澤", "對作者而言，觀察濱鷸的眼神比身上的光澤來得重要 灰褐羽毛象徵濱鷸的生命經驗，這是相機無法傳達的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00289', 'elementary-f29af906', 'elementary-f29af906-moex-113-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「古代希臘哲學家亞里斯多德說：『快樂就是生命的意義和目的，也是人類生存的總目標』； 還有一位奧妙的悲觀主義者，德國哲學家叔本華的一句智慧之言：『快樂乃是健康所開放的 花朵，而健康則從勤勞、節慾、衛生產生。』一點也不假，健康必須力求身心兩健，保養生 理的健康，必也同時保持心理的健全，才能整合身心兩者的愉快，延年益壽。」 根據上文，下列敘述適當的是：', '["生命的意義和目的，在於實踐自己的願望", "勤奮地工作，可以彰顯生命的意義和目的", "做好環境清潔，是讓自己獲得快樂的捷徑", "同時保持生理和心理健康，可以延年益壽 人生最大的快樂，來自於擁有樂觀與智慧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00290', 'elementary-f29af906', 'elementary-f29af906-moex-113-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「『核心素養』是社會群體成員共有的知識、能力與態度，是全方位的素養；『專門素養』 是特定行業人員所具備的特定行業或專門職業的專門素養之知識、能力與態度。『核心素養』 主要目的是強調社會功能，以建立功能健全的社會；『專門素養』主要目的是強調個人具備 特定行業所需的素養，以加入特定專門職業團體，以協助個人獲得成功的生活。」 根據上文，下列選項何者對素養類別的判斷正確？', '["核心素養：開車時願意禮讓行人", "專門素養：能與他人溝通並互動", "核心素養：可以自行研發新產品", "專門素養：能成功行銷工商百貨 核心素養：開發水產養殖新方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00291', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '外國人在我國取得土地，依土地法規定，下列敘述何者錯誤？', '["外國人基於自用、投資或公益之目的使用，得取得第19條第1項各款用途之土地", "其面積及所在地點，應受該管直轄市或縣（市）政府依法所定之限制", "取得有助於國內重大建設、整體經濟或農牧經營之投資所需土地，應先經中央目的事業主管機關同意", "外國人依第19條需要取得土地，應檢附相關文件，申請內政部核准"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00292', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，直轄市或縣（市）主管機關於接到中央主管機關通知核准徵收案時，應即公 告，並以書面通知土地或土地改良物所有權人及他項權利人，公告之期間為下列何者？', '["15日", "30日", "60日", "90日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00293', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '山坡地範圍內森林區、山坡地保育區及風景區之土地，在未編定使用地之類別前，適用何種用地之 管制？', '["國土保安用地", "林業用地", "生態保護用地", "遊憩用地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00294', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依農業發展條例規定，關於耕地分割之敘述，下列何者錯誤？', '["每宗耕地於分割後，每人所有面積未達0.2公頃者，原則上不得分割", "同一所有權人之二宗以上毗鄰耕地，土地宗數未增加者，得為分割合併", "耕地三七五租約，租佃雙方協議以分割方式終止租約者，得分割為租佃雙方單獨所有", "本條例民國89年1月4日修正施行前之共有耕地，得分割為單獨所有"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00295', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則規定，下列何者不屬登記機關應以書面敘明理由及法令依據，駁回登記之申請情形？', '["依法不應登記", "不屬受理登記機關管轄", "未依規定繳納登記規費", "逾期未補正或未照補正事項完全補正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00296', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則規定，下列何者不屬應由登記機關逕為登記之情形？', '["因土地徵收或撥用之登記", "建物因行政區域調整、門牌整編所為之標示變更登記", "建物基地號因重測、重劃或依法逕為分割或合併所為之標示變更登記", "登記名義人住址變更，未申請登記者，登記機關得查明其現在住址，逕為住址變更登記"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00297', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則規定，申請土地權利變更登記，下列敘述何者錯誤？', '["應於權利變更之日起1個月內為之", "繼承登記得自繼承開始之日起6個月內為之", "權利變更之日，依鄉鎮市調解條例規定成立之調解，指調解成立之日", "權利變更之日，依仲裁法作成之判斷，判斷書交付或送達之日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
